%[text] # Pruebas de Cinemática Directa
%[text] ## Seeds Initialization
clear; close all; clc;
S01_my_robot; Robot.display; %[output:59e9d30c]

N = 1001;
angles = linspace(-pi, pi, N);
xlimit = [-pi, pi];
lbls = {'-\pi', '-3\pi/4', '-\pi/2', '-\pi/4', '0', '\pi/4', '\pi/2', '3\pi/4', '\pi'};

QSolution = zeros(N, 6);

% Values [-π, π]
for k = 1:6
    QSolution(:, k) = -pi + (2*pi/(N-1)) * (0:N-1)';
end

% Random values
% for k = 1:6
%     QSolution(:, k) = -pi + 2*pi * rand(N, 1);
% end

hat = Robot.offset';
Robot.offset = zeros(6, 1);

Target = Robot.fkine(QSolution);

T_tool = Robot.tool;

a1 = Robot.links(1).a; 
a2 = Robot.links(2).a; 
a3 = Robot.links(3).a; 

d1 = Robot.links(1).d; 
d4 = Robot.links(4).d; 
d6 = Robot.links(6).d; 

L1 = a2; 
L2 = sqrt(a3^2 + d4^2);



T06   = repmat(SE3(), N, 1);
T03   = repmat(SE3(), N, 1);
p_w   = zeros(N, 3);

q1    = zeros(N, 2);
q2    = zeros(N, 4);
q3    = zeros(N, 4);

q4    = zeros(N, 2);
q5    = zeros(N, 2);
q6    = zeros(N, 2);

err_q1    = zeros(N, 2);
err_q2    = zeros(N, 4);
err_q3    = zeros(N, 4);
err_q4    = zeros(N, 2);
err_q5    = zeros(N, 2);
err_q6    = zeros(N, 2);

phi = atan2(a3, d4); 
%[text] ## Solution $q\_1$
for k = 1:N
    T06(k) = Target(k) / T_tool; 
    
    % Kinematic Decoupling:
    % p_w = p - d6 * z
    pos_tcp = T06(k).t;
    z_tcp   = T06(k).a;
    
    p_w(k, :) = (pos_tcp - z_tcp * d6)';
    
    if norm(p_w(k, 1:2)) < 1e-6
        disp('Advertencia: Punto sobre el eje Z0 (Singularidad)')
    end
    
    q1(k, 1) = atan2(p_w(k, 2), p_w(k, 1));
    q1(k, 2) = atan2(-p_w(k, 2), -p_w(k, 1));
end


err_q1(:, 1) = rad2deg(((QSolution(:, 1) - q1(:, 1))));
err_q1(:, 2) = rad2deg(((QSolution(:, 1) - q1(:, 2))));

figure('Name', "Error q1");  %[output:8ebfa322]
plot(angles, [err_q1(:, 1) err_q1(:, 2)], 'LineWidth', 1); %[output:8ebfa322]

title('Error Absoluto q_1'); xlabel('Ángulo [rad]'); ylabel('Error Relativo [deg]'); %[output:8ebfa322]

lgd = legend('e_{1}', 'e_{2}', 'Location', 'northeastoutside'); %[output:8ebfa322]
lgd.ItemHitFcn = @toggleSignal;

xlim(xlimit); %[output:8ebfa322]
set(gca, 'XTick', -pi : pi/4 : pi); %[output:8ebfa322]
set(gca, 'XTickLabel', lbls, 'TickLabelInterpreter', 'tex'); %[output:8ebfa322]

grid on;grid minor; %[output:8ebfa322]
%[text] ## Solution $q\_2, q\_3$
for k = 1:N
    r     = zeros(2, 1);
    D     = zeros(2, 1);
    alpha = zeros(2, 1);

    px = p_w(k, 1);
    py = p_w(k, 2);
    pz = p_w(k, 3);

    % Front Configuration
    r(1) =  sqrt(px^2 + py^2) - a1; 
    % Back Configuration
    r(2) = -sqrt(px^2 + py^2) - a1;
    
    s = pz - d1; 


    for j = 1:2
        D(j)     = sqrt(r(j)^2 + s^2);
        alpha(j) = atan2(s, r(j));
        
        % j=1 -> idx1=1, idx2=2
        % j=2 -> idx1=3, idx2=4
        
        idx1 = 2*j - 1;
        idx2 = 2*j;

        if D(j) <= (L1 + L2) && D(j) >= abs(L1 - L2)
            beta  = Tcoseno_a(L1, L2, D(j));
            gamma = Tcoseno_a(D(j), L1, L2);

            % Elbow Up
            q2(k, idx1) = alpha(j) + gamma;
            q3(k, idx1) = beta - pi/2 - phi;

            % Elbow Down
            q2(k, idx2) = alpha(j) - gamma;
            q3(k, idx2) = -beta + pi/2 - phi;
        else
            q2(k, idx1:idx2) = NaN;
            q3(k, idx1:idx2) = NaN;
        end
    end
end

err_q2(:, 1) = rad2deg((QSolution(:, 2) - q2(:, 1)));
err_q2(:, 2) = rad2deg((QSolution(:, 2) - q2(:, 2)));
err_q2(:, 3) = rad2deg((QSolution(:, 2) - q2(:, 3)));
err_q2(:, 4) = rad2deg((QSolution(:, 2) - q2(:, 4)));

figure('Name', "Error q2");  %[output:4944b29c]

plot(angles, [err_q2(:, 1) err_q2(:, 2) err_q2(:, 3) err_q2(:, 4)], 'LineWidth', 1); %[output:4944b29c]

title('Error Absoluto q_2'); xlabel('Ángulo [rad]'); ylabel('Error Relativo [deg]'); %[output:4944b29c]

lgd2 = legend('e_{1}', 'e_{2}', 'e_{3}', 'e_{4}', 'Location', 'northeastoutside'); %[output:4944b29c]
